doc = Rhino.RhinoDoc.ActiveDoc
rows = []
for view in doc.Views:
    vp = view.ActiveViewport
    if vp.IsParallelProjection:
        projection = "parallel"
    elif vp.IsPerspectiveProjection:
        projection = "perspective"
    else:
        projection = "other"
    rows.append({
        "name": view.MainViewport.Name,
        "projection": projection,
        "camera_location": {"x": vp.CameraLocation.X, "y": vp.CameraLocation.Y, "z": vp.CameraLocation.Z},
        "target": {"x": vp.CameraTarget.X, "y": vp.CameraTarget.Y, "z": vp.CameraTarget.Z}
    })
return {"count": len(rows), "viewports": rows}
